const input = $json.body ?? $json;

const compactPayload = {
  contact_name: input.name || input.contact_name || '',
  contact_email: (input.email || input.contact_email || '').toLowerCase().trim(),
  company: (input.company || '').trim(),
  role: (input.role || input.job_title || 'Unknown').trim(),
  inquiry_summary: (input.message || input.inquiry_summary || '').trim(),
  budget_estimate_usd: input.estimated_budget_usd ?? input.budget_estimate_usd ?? null,
  source: (input.source || 'webhook').trim()
};

return [{
  json: {
    ...compactPayload,
    ai_prompt_payload: {
      context: 'B2B automation lead qualification',
      criteria: ['business fit', 'urgency', 'budget readiness', 'implementation clarity'],
      lead: compactPayload
    }
  }
}];

const summaryText = `${$json.inquiry_summary || ''}`.toLowerCase();
const budget = Number($json.budget_estimate_usd || 0);

let leadScore = 40;
if (summaryText.includes('automation')) leadScore += 15;
if (summaryText.includes('crm') || summaryText.includes('integration')) leadScore += 15;
if (summaryText.includes('urgent') || summaryText.includes('asap')) leadScore += 10;
if (budget >= 10000) leadScore += 15;
if (budget >= 25000) leadScore += 5;

leadScore = Math.max(0, Math.min(100, leadScore));

let leadCategory = 'early-stage';
let priority = 'low';
let crmStage = 'Nurture';
let confidence = 0.67;
let recommendedAction = 'Request clarification before qualification';

if (leadScore >= 80) {
  leadCategory = 'high-fit';
  priority = 'high';
  crmStage = 'Discovery';
  confidence = 0.91;
  recommendedAction = 'Schedule fast response within 2 hours';
} else if (leadScore >= 60) {
  leadCategory = 'qualified';
  priority = 'medium';
  crmStage = 'Qualified';
  confidence = 0.82;
  recommendedAction = 'Add to nurture pipeline';
}

const summary = `${$json.contact_name || 'Lead'} from ${$json.company || 'Unknown company'} classified as ${leadCategory} (${priority}) with score ${leadScore}.`;

return [{
  json: {
    ...$json,
    lead_score: leadScore,
    lead_category: leadCategory,
    priority,
    confidence,
    summary,
    recommended_action: recommendedAction,
    crm_stage: crmStage
  }
}];

return [{
  json: {
    ...$json,
    routing_bucket: 'high-priority',
    crm_record: {
      contact_name: $json.contact_name,
      contact_email: $json.contact_email,
      company: $json.company,
      score: $json.lead_score,
      priority: $json.priority,
      stage: $json.crm_stage,
      owner_hint: 'senior-ae-queue',
      notes: $json.summary
    }
  }
}];

return [{
  json: {
    ...$json,
    routing_bucket: 'medium-priority',
    crm_record: {
      contact_name: $json.contact_name,
      contact_email: $json.contact_email,
      company: $json.company,
      score: $json.lead_score,
      priority: $json.priority,
      stage: $json.crm_stage,
      owner_hint: 'sales-ops-queue',
      notes: $json.summary
    }
  }
}];

return [{
  json: {
    ...$json,
    routing_bucket: 'low-priority',
    crm_record: {
      contact_name: $json.contact_name,
      contact_email: $json.contact_email,
      company: $json.company,
      score: $json.lead_score,
      priority: $json.priority,
      stage: $json.crm_stage,
      owner_hint: 'nurture-queue',
      notes: $json.summary
    }
  }
}];

let nextStep = 'Request clarification before qualification';
if ($json.priority === 'high') nextStep = 'Schedule fast response within 2 hours';
if ($json.priority === 'medium') nextStep = 'Add to nurture pipeline';

return [{
  json: {
    qualified_lead: {
      contact_name: $json.contact_name,
      contact_email: $json.contact_email,
      company: $json.company,
      role: $json.role,
      inquiry_summary: $json.inquiry_summary,
      budget_estimate_usd: $json.budget_estimate_usd,
      lead_score: $json.lead_score,
      lead_category: $json.lead_category,
      priority: $json.priority,
      confidence: $json.confidence,
      summary: $json.summary,
      recommended_action: $json.recommended_action,
      crm_stage: $json.crm_stage,
      routing_bucket: $json.routing_bucket,
      crm_record: $json.crm_record
    },
    internal_follow_up: {
      next_step: nextStep,
      owner_hint: $json.crm_record.owner_hint
    },
    processed_at: new Date().toISOString()
  }
}];
